@app.errorhandler(Exception)
def handle_exception(exc):
    apm.capture_exception()
    return jsonify({"error": str(exc)}), 500


@app.route("/health", methods=["GET"])
def health():
    return jsonify({"status": "ok"})


@app.route("/items", methods=["POST"])
def create_item():
    payload = request.get_json(force=True, silent=False) or {}
    name = payload.get("name", f"item-{random.randint(1000, 9999)}")
    value = int(payload.get("value", random.randint(1, 100)))

    with apm_span("insert_item", "db", "sqlite", "query"):
        db = get_db()
        cursor = db.execute("INSERT INTO items (name, value) VALUES (?, ?)", (name, value))
        db.commit()

    return jsonify({"id": cursor.lastrowid, "name": name, "value": value}), 201


@app.route("/items", methods=["GET"])
def list_items():
    limit = int(request.args.get("limit", "10"))

    with apm_span("select_items", "db", "sqlite", "query"):
        db = get_db()
        rows = db.execute(
            "SELECT id, name, value, created_at FROM items ORDER BY id DESC LIMIT ?",
            (limit,),
        ).fetchall()

    items = [dict(row) for row in rows]
    return jsonify(items)


@app.route("/items/<int:item_id>", methods=["GET"])
def get_item(item_id):
    with apm_span("select_item_by_id", "db", "sqlite", "query"):
        db = get_db()
        row = db.execute(
            "SELECT id, name, value, created_at FROM items WHERE id = ?",
            (item_id,),
        ).fetchone()

    if not row:
        return jsonify({"error": "not found"}), 404

    return jsonify(dict(row))


@app.route("/simulate", methods=["GET"])
def simulate_work():
    delay = float(request.args.get("delay", "0.25"))
    fail = request.args.get("fail", "false").lower() == "true"

    with apm_span("cpu_work", "app", "compute", "busy_loop"):
        total = 0
        for i in range(50000):
            total += i * i

    with apm_span("sleep_work", "external", "timer", "sleep"):
        time.sleep(delay)

    if fail:
        raise RuntimeError("Simulated failure for APM stack trace capture")

    return jsonify({"delay": delay, "computed": total})


